commands:
kubectl exec -n librenms \
  $(kubectl get pod -n librenms -l app=librenms -o name | head -1) \
  -- sh -c 'cat > /tmp/resetpw.php << '"'"'EOF'"'"'
<?php
require "/opt/librenms/vendor/autoload.php";
$app = require "/opt/librenms/bootstrap/app.php";
$app->make(Illuminate\Contracts\Console\Kernel::class)->bootstrap();
$u = App\Models\User::where("username", "matt")->first();
$u->password = bcrypt("NewPassword123");
$u->save();
echo "OK: " . $u->username . "\n";
EOF'
